package com.enterprise.banking.service;

import com.enterprise.banking.exception.BankingFaultInfo;
import com.enterprise.banking.exception.BankingServiceException;
import com.enterprise.banking.model.*;
import com.enterprise.banking.security.SOAPMessageParser;
import com.enterprise.banking.security.XMLSignatureVerifier;

import javax.annotation.Resource;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    endpointInterface = "com.enterprise.banking.service.BankingService",
    targetNamespace = "http://banking.enterprise.com/transactions",
    wsdlLocation = "WEB-INF/wsdl/BankingService.wsdl"
)
@org.apache.cxf.interceptor.InInterceptors(interceptors = {
    "com.enterprise.banking.security.WSSSecurityInterceptor"
})
public class BankingServiceImpl implements BankingService {

    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());

    @Resource
    private WebServiceContext webServiceContext;

    private final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();
    private final Map<String, List<TransactionResponse>> transactionHistory = new ConcurrentHashMap<>();
    private final XMLSignatureVerifier signatureVerifier = new XMLSignatureVerifier();
    private final SOAPMessageParser messageParser = new SOAPMessageParser();

    public BankingServiceImpl() {
        // Initialize demo accounts
        accountBalances.put("ACC-001", new BigDecimal("50000.00"));
        accountBalances.put("ACC-002", new BigDecimal("75000.00"));
        accountBalances.put("ACC-003", new BigDecimal("120000.00"));
        accountBalances.put("ACC-004", new BigDecimal("30000.00"));
    }

    @Override
    public TransactionResponse processTransaction(BankTransaction transaction)
            throws BankingServiceException {

        LOGGER.info("Processing transaction: " + transaction.getTransactionId());

        try {
            // Validate the WS-Security context
            validateSecurityContext();

            // Validate transaction fields
            validateTransactionFields(transaction);

            // Process based on transaction type
            TransactionResponse response;
            switch (transaction.getTransactionType()) {
                case TRANSFER:
                    response = processTransfer(transaction);
                    break;
                case DEPOSIT:
                    response = processDeposit(transaction);
                    break;
                case WITHDRAWAL:
                    response = processWithdrawal(transaction);
                    break;
                case PAYMENT:
                    response = processPayment(transaction);
                    break;
                case REFUND:
                    response = processRefund(transaction);
                    break;
                default:
                    throw new BankingServiceException(
                        "Unsupported transaction type",
                        new BankingFaultInfo("INVALID_TYPE", "Unsupported transaction type",
                            transaction.getTransactionType().toString())
                    );
            }

            // Store in history
            storeTransactionHistory(transaction, response);

            LOGGER.info("Transaction processed successfully: " + transaction.getTransactionId());
            return response;

        } catch (BankingServiceException e) {
            throw e;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing transaction", e);
            throw new BankingServiceException(
                "Transaction processing failed",
                new BankingFaultInfo("PROCESSING_ERROR", e.getMessage(), transaction.getTransactionId()),
                e
            );
        }
    }

    @Override
    public AccountBalance getAccountBalance(String accountId) throws BankingServiceException {
        LOGGER.info("Retrieving balance for account: " + accountId);

        validateSecurityContext();

        BigDecimal balance = accountBalances.get(accountId);
        if (balance == null) {
            throw new BankingServiceException(
                "Account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Account does not exist", accountId)
            );
        }

        return new AccountBalance(accountId, balance, "USD");
    }

    @Override
    public List<TransactionResponse> getTransactionHistory(String accountId, int limit)
            throws BankingServiceException {
        LOGGER.info("Retrieving transaction history for account: " + accountId);

        validateSecurityContext();

        if (!accountBalances.containsKey(accountId)) {
            throw new BankingServiceException(
                "Account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Account does not exist", accountId)
            );
        }

        List<TransactionResponse> history = transactionHistory.getOrDefault(accountId, Collections.emptyList());
        if (history.size() > limit) {
            return history.subList(0, limit);
        }
        return history;
    }

    @Override
    public TransactionResponse validateTransaction(BankTransaction transaction)
            throws BankingServiceException {
        LOGGER.info("Validating transaction: " + transaction.getTransactionId());

        validateSecurityContext();

        try {
            validateTransactionFields(transaction);

            // Check source account exists and has sufficient funds
            BigDecimal sourceBalance = accountBalances.get(transaction.getSourceAccountId());
            if (sourceBalance == null) {
                return new TransactionResponse(
                    transaction.getTransactionId(),
                    TransactionStatus.REJECTED,
                    400,
                    "Source account not found",
                    true
                );
            }

            if (transaction.getTransactionType() != TransactionType.DEPOSIT &&
                sourceBalance.compareTo(transaction.getAmount()) < 0) {
                return new TransactionResponse(
                    transaction.getTransactionId(),
                    TransactionStatus.REJECTED,
                    400,
                    "Insufficient funds",
                    true
                );
            }

            return new TransactionResponse(
                transaction.getTransactionId(),
                TransactionStatus.PENDING,
                200,
                "Transaction validation successful",
                true
            );

        } catch (BankingServiceException e) {
            return new TransactionResponse(
                transaction.getTransactionId(),
                TransactionStatus.REJECTED,
                400,
                e.getMessage(),
                true
            );
        }
    }

    private void validateSecurityContext() throws BankingServiceException {
        if (webServiceContext == null) {
            LOGGER.warning("WebServiceContext is null - security validation skipped in test mode");
            return;
        }

        MessageContext msgContext = webServiceContext.getMessageContext();
        if (msgContext == null) {
            throw new BankingServiceException(
                "Security context unavailable",
                new BankingFaultInfo("SECURITY_ERROR", "No message context available", null)
            );
        }

        // Check if WS-Security validated the signature
        Boolean signatureValid = (Boolean) msgContext.get("ws-security.signature.valid");
        if (signatureValid != null && !signatureValid) {
            throw new BankingServiceException(
                "Invalid message signature",
                new BankingFaultInfo("SIGNATURE_INVALID",
                    "The SOAP message signature could not be verified", null)
            );
        }

        LOGGER.info("Security context validated successfully");
    }

    private void validateTransactionFields(BankTransaction transaction) throws BankingServiceException {
        if (transaction == null) {
            throw new BankingServiceException(
                "Transaction is null",
                new BankingFaultInfo("INVALID_INPUT", "Transaction object is required", null)
            );
        }
        if (transaction.getTransactionId() == null || transaction.getTransactionId().isEmpty()) {
            throw new BankingServiceException(
                "Transaction ID is required",
                new BankingFaultInfo("INVALID_INPUT", "Transaction ID cannot be empty", null)
            );
        }
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new BankingServiceException(
                "Invalid amount",
                new BankingFaultInfo("INVALID_AMOUNT", "Amount must be greater than zero",
                    String.valueOf(transaction.getAmount()))
            );
        }
        if (transaction.getSourceAccountId() == null || transaction.getSourceAccountId().isEmpty()) {
            throw new BankingServiceException(
                "Source account is required",
                new BankingFaultInfo("INVALID_INPUT", "Source account ID cannot be empty", null)
            );
        }
        if (transaction.getCurrency() == null || transaction.getCurrency().isEmpty()) {
            throw new BankingServiceException(
                "Currency is required",
                new BankingFaultInfo("INVALID_INPUT", "Currency cannot be empty", null)
            );
        }
    }

    private synchronized TransactionResponse processTransfer(BankTransaction transaction)
            throws BankingServiceException {
        BigDecimal sourceBalance = accountBalances.get(transaction.getSourceAccountId());
        BigDecimal targetBalance = accountBalances.get(transaction.getTargetAccountId());

        if (sourceBalance == null) {
            throw new BankingServiceException(
                "Source account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Source account does not exist",
                    transaction.getSourceAccountId())
            );
        }
        if (targetBalance == null) {
            throw new BankingServiceException(
                "Target account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Target account does not exist",
                    transaction.getTargetAccountId())
            );
        }
        if (sourceBalance.compareTo(transaction.getAmount()) < 0) {
            return new TransactionResponse(
                transaction.getTransactionId(),
                TransactionStatus.REJECTED,
                400,
                "Insufficient funds. Available: " + sourceBalance,
                true
            );
        }

        accountBalances.put(transaction.getSourceAccountId(), sourceBalance.subtract(transaction.getAmount()));
        accountBalances.put(transaction.getTargetAccountId(), targetBalance.add(transaction.getAmount()));

        return new TransactionResponse(
            transaction.getTransactionId(),
            TransactionStatus.SUCCESS,
            200,
            "Transfer completed successfully",
            true
        );
    }

    private synchronized TransactionResponse processDeposit(BankTransaction transaction)
            throws BankingServiceException {
        String accountId = transaction.getTargetAccountId() != null ?
            transaction.getTargetAccountId() : transaction.getSourceAccountId();

        BigDecimal balance = accountBalances.get(accountId);
        if (balance == null) {
            throw new BankingServiceException(
                "Account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Account does not exist", accountId)
            );
        }

        accountBalances.put(accountId, balance.add(transaction.getAmount()));

        return new TransactionResponse(
            transaction.getTransactionId(),
            TransactionStatus.SUCCESS,
            200,
            "Deposit completed successfully",
            true
        );
    }

    private synchronized TransactionResponse processWithdrawal(BankTransaction transaction)
            throws BankingServiceException {
        BigDecimal balance = accountBalances.get(transaction.getSourceAccountId());
        if (balance == null) {
            throw new BankingServiceException(
                "Account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "Account does not exist",
                    transaction.getSourceAccountId())
            );
        }
        if (balance.compareTo(transaction.getAmount()) < 0) {
            return new TransactionResponse(
                transaction.getTransactionId(),
                TransactionStatus.REJECTED,
                400,
                "Insufficient funds",
                true
            );
        }

        accountBalances.put(transaction.getSourceAccountId(), balance.subtract(transaction.getAmount()));

        return new TransactionResponse(
            transaction.getTransactionId(),
            TransactionStatus.SUCCESS,
            200,
            "Withdrawal completed successfully",
            true
        );
    }

    private synchronized TransactionResponse processPayment(BankTransaction transaction)
            throws BankingServiceException {
        return processTransfer(transaction);
    }

    private synchronized TransactionResponse processRefund(BankTransaction transaction)
            throws BankingServiceException {
        // Reverse: add to source, deduct from target
        BigDecimal sourceBalance = accountBalances.get(transaction.getSourceAccountId());
        BigDecimal targetBalance = accountBalances.get(transaction.getTargetAccountId());

        if (sourceBalance == null || targetBalance == null) {
            throw new BankingServiceException(
                "Account not found",
                new BankingFaultInfo("ACCOUNT_NOT_FOUND", "One or more accounts not found", null)
            );
        }

        accountBalances.put(transaction.getSourceAccountId(), sourceBalance.add(transaction.getAmount()));
        accountBalances.put(transaction.getTargetAccountId(), targetBalance.subtract(transaction.getAmount()));

        return new TransactionResponse(
            transaction.getTransactionId(),
            TransactionStatus.SUCCESS,
            200,
            "Refund processed successfully",
            true
        );
    }

    private void storeTransactionHistory(BankTransaction transaction, TransactionResponse response) {
        transactionHistory.computeIfAbsent(transaction.getSourceAccountId(), k -> new ArrayList<>()).add(response);
        if (transaction.getTargetAccountId() != null &&
            !transaction.getTargetAccountId().equals(transaction.getSourceAccountId())) {
            transactionHistory.computeIfAbsent(transaction.getTargetAccountId(), k -> new ArrayList<>()).add(response);
        }
    }
}

